struct Edge {
    EdgeId   id;
    NodeId   src;
    NodeId   dst;
    double   weight;
    PropertyMap props;

    Edge() : id(0), src(INVALID_NODE), dst(INVALID_NODE), weight(1.0) {}

    Edge(EdgeId eid, NodeId s, NodeId d, double w = 1.0)
        : id(eid), src(s), dst(d), weight(w) {}

    bool operator==(const Edge& o) const {
        return id == o.id && src == o.src && dst == o.dst;
